import { HttpClient, HttpContext, HttpResponse } from '@angular/common/http';
import { Observable } from 'rxjs';
import { filter, map } from 'rxjs/operators';
import { StrictHttpResponse } from '../../strict-http-response';
import { RequestBuilder } from '../../request-builder';
import { CarAccessDto, CarAccessRole } from '../../models/car-access-dto';

export interface CarAccessControllerInviteUser$Params {
  carId: number;
  body: { email: string; role: CarAccessRole };
}

export function carAccessControllerInviteUser(http: HttpClient, rootUrl: string, params: CarAccessControllerInviteUser$Params, context?: HttpContext): Observable<StrictHttpResponse<CarAccessDto>> {
  const rb = new RequestBuilder(rootUrl, carAccessControllerInviteUser.PATH, 'post');
  rb.path('carId', params.carId, {});
  rb.body(params.body, 'application/json');
  return http.request(rb.build({ responseType: 'json', accept: 'application/json', context })).pipe(
    filter((r: any): r is HttpResponse<any> => r instanceof HttpResponse),
    map((r: HttpResponse<any>) => r as StrictHttpResponse<CarAccessDto>),
  );
}

carAccessControllerInviteUser.PATH = '/api/car/{carId}/access/invite';
